public class LRUCache<K, V> {
    private final int capacity;
    private final Map<K, V> cache;

    public LRUCache(int capacity) {
        this.capacity = capacity;
        this.cache = Collections.synchronizedMap(
            new LinkedHashMap<>(capacity, 0.75f, true) {
                @Override
                protected boolean removeEldestEntry(Map.Entry<K,V> eldest) {
                    return size() > capacity;
                }
            }
        );
    }

    public V get(K key) { return cache.get(key); }
    public void put(K key, V value) { cache.put(key, value); }
}

public class ConsistentHashRouter<T> {
    private final TreeMap<Long, T> ring = new TreeMap<>();
    private final int virtualNodes;

    public void addNode(T node) {
        for (int i = 0; i < virtualNodes; i++) {
            long hash = hash(node.toString() + ":" + i);
            ring.put(hash, node);
        }
    }

    public T route(String key) {
        long hash = hash(key);
        Map.Entry<Long, T> entry = ring.ceilingEntry(hash);
        return entry != null ? entry.getValue() : ring.firstEntry().getValue();
    }

    private long hash(String s) {
        return Hashing.murmur3_128().hashString(s, UTF_8).asLong();
    }
}

// Cache locking with Redis to prevent thundering herd
public String getWithLock(String key) {
    String value = redis.get(key);
    if (value != null) return value;

    String lockKey = "lock:" + key;
    boolean locked = redis.setnx(lockKey, "1") == 1;
    redis.expire(lockKey, 5); // 5s lock timeout

    if (locked) {
        try {
            value = db.fetch(key);
            redis.setex(key, TTL, value);
        } finally {
            redis.del(lockKey);
        }
    } else {
        // Wait and retry
        Thread.sleep(50);
        value = redis.get(key); // now populated by lock holder
    }
    return value;
}
